       DECODE(b.fmopcode, NULL, a.fmopcode, b.fmopcode) fmopcode,
       DECODE(b.fmname,   NULL, a.fmname,   b.fmname)   fmname,
       DECODE(b.fmsign,   NULL, a.fmsign,   b.fmsign)   fmsign,
