-- VIEW PUB_GOODS_V

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."PUB_GOODS_V" ("GOODSID", "GOODSNAME", "GOODSNO", "PRICE", "SUQTY", "USEFLAG", "FACTORYNAME", "STANDARDTYPE", "ZX_PL", "ZX_MINIMUM", "APPROVEDOCNO", "BASEUNITQTY", "ZX_CUSTOMERID", "CUSTOMNAME", "TARGETMARKET", "HOLDERSNAME", "ISERP", "GOODSTYPE", "PACKTYPE", "TRANPOSNAME", "BOMID", "LASTSUQTY", "TRANPOSID") AS 
  SELECT B.GOODSID ,
       B.GOODSNAME ,b.GOODSNO,
       c.lastprice PRICE,
       c.lastsuqty suqty,
       (case
         when b.zx_wms_goodsclass in (1, 12) and b.gspflag = 1 and
              b.goodsno like '%A%' then
          '原料'
         when b.zx_wms_goodsclass in (10) and b.gspflag = 1 then
          '产成品'
         when b.zx_wms_goodsclass in (7, 8, 9) and b.gspflag = 1 then
          '半成品'
         when b.zx_wms_goodsclass in (5, 13) and b.gspflag = 1 then
          '非印字包材'
         when b.zx_wms_goodsclass in (6) and b.gspflag = 1 then
          '印字包材'
         when b.zx_wms_goodsclass in (1, 2, 3, 4) and b.gspflag = 1 and
              b.goodsno not like '%A%' then
          '辅料'
       end) USEFLAG,
       B.FACTORYNAME,
       B.standardtype,
       b.zx_pl,
       b.zx_minimum,
       b.approvedocno, --批准文号
       e.baseunitqty,
       b.zx_customerid,
       b.customname,
       f.targetmarket,
       b.holdersname,
       1 ISERP,
       b.goodstype,
       b.packtype,
       b.tranposname,
       d.bomid,
       c.lastsuqty,
       b.tranposid
  FROM PUB_GOODS_V@hyerp            B,
       bms_su_supplygoods_doc@Hyerp c,
       MPCS_PR_BOM_DOC@Hyerp        d,
       pub_goods_unit_v@hyerp       e,
       bms_tr_pos_def@hyerp         f
 where B.GOODSID = C.GOODSID(+)
   and b.goodsid = d.pgoodsid(+)
   and d.usestatus(+) = 1
   and b.usestatus = 1
   and c.entryid(+) = 1
   and b.goodsid = e.goodsid(+)
   and e.goodsdtlflag(+) = 1
   and e.baseflag(+) <> 1
   and b.goodsid < 1000000
   and b.zx_customerid = f.companyid(+)
   and b.tranposid = f.tranposid(+)
;
/

-- VIEW T_COST_BOM_GOODS_TREE_V

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."T_COST_BOM_GOODS_TREE_V" ("TREEID", "PID", "GOODSID", "GOODSNAME", "USEFLAG", "STANDARDTYPE", "LVCODE", "USEQTY", "ENTRYID") AS 
