-- VIEW T_COST_FORMONEY_V

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."T_COST_FORMONEY_V" ("FMID", "FMOPCODE", "FMNAME", "FMSIGN", "FMUNIT", "FMRATE", "USESTATUS", "DELETED", "CREATE_TIME", "UPDATE_TIME", "CREATE_BY", "UPDATE_BY") AS 
  SELECT
