    a.UPDATE_TIME,
    a.CREATE_BY,
    a.UPDATE_BY
FROM T_COST_FORMONEY a
LEFT JOIN pub_formoney_v@hyerp b ON a.FMID = b.FMID
WHERE a.DELETED = 0 OR a.DELETED IS NULL
;
