-- VIEW T_COST_GOODS_PRICE_V

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."T_COST_GOODS_PRICE_V" ("GOODSID", "GOODSNAME", "PRICE", "USEFLAG", "GOODSTYPE", "PACKTYPE", "FACTORYNAME", "DELETED", "CREATE_TIME", "UPDATE_TIME", "CREATE_BY", "UPDATE_BY", "ISERP", "ROW_CLASS_FLAG", "STANDARDTYPE", "GOODSNAME_EN") AS 
  SELECT GOODSID,
       GOODSNAME,
       PRICE,
       USEFLAG,
       GOODSTYPE,
       PACKTYPE,
       FACTORYNAME,
       DELETED,
       CREATE_TIME,
       UPDATE_TIME,
       CREATE_BY,
       UPDATE_BY,
       ISERP,
       CASE
           WHEN ISERP = 1
            AND UPDATE_BY <> 'ERP_SYNC'
            AND PRICE IS NULL THEN 'erp-price-null'
           WHEN ISERP = 1
            AND UPDATE_BY <> 'ERP_SYNC' THEN 'erp-updated'
           WHEN ISERP = 1 THEN 'erp'
           ELSE NULL
       END AS ROW_CLASS_FLAG,
       STANDARDTYPE,
       GOODSNAME_EN
  FROM T_COST_GOODS WHERE USEFLAG NOT IN ('产成品','半成品')
;
/

