-- VIEW T_WMS_QTY_DETAIL_V

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."T_WMS_QTY_DETAIL_V" ("RN", "CONID", "GOODSID", "GOODSNAME", "LOTNO", "GOODSQTY", "PCS", "VALIDDATE", "CONTAINERNO", "MEMO", "JZ", "MZ", "TJ", "DELETED") AS 
  SELECT
    ROW_NUMBER() OVER (PARTITION BY a.conid ORDER BY b.containerno, a.goodsid, a.lotno) AS rn,
    a.conid,
    a.goodsid,
    a.goodsname,
    a.lotno,
    b.goodsqty,
    b.pcs,
    b.validdate,
    b.containerno,
    null memo,
    NULL AS jz,
    NULL AS mz,
    NULL AS tj,
    0 AS DELETED
FROM (
    SELECT a.conid, a.goodsid, a.goodsno, a.goodsname, a.lotno, a.packtype
    FROM bms_sa_con_dtl_v@hyerp a
    GROUP BY a.conid, a.goodsid, a.goodsno, a.goodsname, a.lotno, a.packtype
) a,
(
    SELECT
        x.goodsownid,
        x.lotno,
        x.packname,
        x.packsize,
        x.goodsqty,
        x.validdate,
        CEIL(x.goodsqty / x.packsize) AS pcs,
        x.containerno
    FROM wms_st_qty_lst_baseunit_v@to_wms x
) b
WHERE a.goodsid = b.goodsownid
  AND a.lotno = b.lotno
;
/

-- VIEW T_WMS_QTY_V

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."T_WMS_QTY_V" ("CONID", "GOODSID", "GOODSGP", "LOTNO", "GOODSNO", "PACKSIZE", "QTY_SHOW", "PCS", "TRANPOSNAME", "DELETED") AS 
  SELECT a.conid,
       a.goodsid,
       a.goodsname || '(' || a.packtype || ')' AS goodsgp,
       a.lotno,
       a.goodsno,
       b.packsize,
       TO_CHAR(NVL(b.goodsqty_total, 0)) || b.basepackname || '（含零头' ||
       TO_CHAR(NVL(b.goodsqty_oddtray1, 0)) || b.basepackname || '，样品__' ||
       b.basepackname || '）' AS QTY_SHOW,
       b.pcs,
       a.tranposname, 0 AS DELETED
  FROM (SELECT a.conid,
               a.goodsid,
               a.goodsno,
               a.goodsname,
               a.lotno,
               a.packtype,
               a.tranposname
          FROM bms_sa_con_dtl_v@hyerp a
         GROUP BY a.conid,
                  a.goodsid,
                  a.goodsno,
                  a.goodsname,
                  a.lotno,
                  a.packtype,a.tranposname) a,
(SELECT x.goodsownid,
        x.lotno,
        x.packname,
        x.basepackname,
        x.packsize,
        SUM(x.goodsqty) AS goodsqty_total,
        SUM(MOD(x.goodsqty, x.packsize)) AS goodsqty_oddtray1,
        SUM(CEIL(x.goodsqty / x.packsize)) AS pcs
 FROM wms_st_qty_lst_baseunit_v@to_wms x
 GROUP BY x.goodsownid, x.lotno, x.packname, x.packsize, x.basepackname) b

 WHERE a.goodsid = b.goodsownid
   AND a.lotno = b.lotno
;
/

