  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."V_COST_GOODS_BY_APEX" ("P_GOODSID", "GOODSNAME", "GOODSTYPE", "PACKTYPE", "TRANPOSID", "TRANPOSNAME", "ZX_CUSTOMERID", "CUSTOMNAME", "ZONE", "GOODSID", "DELETED") AS 
  SELECT c.GOODSID AS P_GOODSID,
       c.GOODSNAME,
       c.GOODSTYPE,
       c.PACKTYPE,
       c.TRANPOSID,
       c.TRANPOSNAME,
       c.ZX_CUSTOMERID,
