  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."V_COST_PGOODS_BY_MGOODS" ("GOODSID", "GOODSNAME", "DTL_USEFLAG", "FACTORYNAME", "PRICE", "GOODSNO", "PGOODSID", "PGOODSNO", "PGOODSNAME", "APEX_PL", "BATCH_QTY", "DELETED") AS 
  SELECT a.goodsid,
       a.goodsname,
       a.dtl_useflag,
       b.factoryname,
       a.price,
       b.goodsno,
       d.goodsid        pgoodsid,
       d.goodsno        pgoodsno,
       d.goodsname pgoodsname,
       c.apex_pl,
       a.batch_qty,
       a.deleted
  FROM T_COST_PINGGU_DTL a, t_cost_goods b, t_cost_pinggu c, t_cost_goods d
 WHERE a.goodsid = b.goodsid
   AND a.docid = c.docid
   AND c.goodsid = d.goodsid
   and a.deleted = 0
   and b.deleted = 0
   and c.deleted = 0
   and d.deleted = 0
;
/

