-- VIEW V_COST_RESOURCE_PERMISSION

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."V_COST_RESOURCE_PERMISSION" ("ID", "PAGE_CODE", "RESOURCE_NAME", "RESOURCE_TYPE", "IS_HARDCODED", "ICON", "ROUTE", "PARENT_ID", "SORT_ORDER", "ROLE_ID", "ROLE_CODE", "ROLE_NAME", "ROLE_PAGE_ID", "BUTTON_POLICY", "COLUMN_POLICY", "ROW_POLICY", "IS_AUTHORIZED") AS 
  SELECT
    res.ID,
    res.PAGE_CODE,
    res.RESOURCE_NAME,
    res.RESOURCE_TYPE,
    res.IS_HARDCODED,
    res.ICON,
    res.ROUTE,
    res.PARENT_ID,
    res.SORT_ORDER,
    r.ID AS ROLE_ID,
    r.ROLE_CODE,
    r.ROLE_NAME,
    rp.ID AS ROLE_PAGE_ID,
    rp.BUTTON_POLICY,
    rp.COLUMN_POLICY,
    rp.ROW_POLICY,
    CASE WHEN rp.ID IS NOT NULL THEN 1 ELSE 0 END AS IS_AUTHORIZED
FROM T_COST_RESOURCE res
CROSS JOIN T_COST_ROLE r
LEFT JOIN T_COST_ROLE_PAGE rp
    ON rp.PAGE_CODE = res.PAGE_CODE
    AND rp.ROLE_ID = r.ID
ORDER BY res.SORT_ORDER
;
/

-- VIEW V_COST_ROLE

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."V_COST_ROLE" ("ID", "ROLE_CODE", "ROLE_NAME", "DESCRIPTION") AS 
  SELECT
    r.ID,
    r.ROLE_CODE,
    r.ROLE_NAME,
    r.DESCRIPTION
FROM T_COST_ROLE r
;
/

-- VIEW V_COST_ROLE_PAGE

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."V_COST_ROLE_PAGE" ("ID", "ROLE_ID", "PAGE_CODE", "PAGE_NAME", "BUTTON_POLICY", "COLUMN_POLICY", "ROW_POLICY") AS 
  SELECT
    rp.ID,
    rp.ROLE_ID,
    rp.PAGE_CODE,
    res.RESOURCE_NAME AS PAGE_NAME,
    rp.BUTTON_POLICY,
    rp.COLUMN_POLICY,
    rp.ROW_POLICY
FROM T_COST_ROLE_PAGE rp
LEFT JOIN T_COST_RESOURCE res ON rp.PAGE_CODE = res.PAGE_CODE
;
/

-- VIEW V_COST_USER

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."V_COST_USER" ("ID", "USERNAME", "PASSWORD", "REAL_NAME", "EMAIL", "PHONE", "DEPARTMENT_ID", "DEPT_NAME", "STATUS", "DELETED", "CREATE_BY", "CREATE_TIME", "UPDATE_BY", "UPDATE_TIME") AS 
  SELECT
    u.ID,
    u.USERNAME,
    u.PASSWORD,
    u.REAL_NAME,
    u.EMAIL,
    u.PHONE,
    u.DEPARTMENT_ID,
    d.DEPT_NAME,
    u.STATUS,
    u.DELETED,
    u.CREATE_BY,
    u.CREATE_TIME,
    u.UPDATE_BY,
    u.UPDATE_TIME
FROM T_COST_USER u
LEFT JOIN T_COST_DEPARTMENT d ON u.DEPARTMENT_ID = d.ID
WHERE u.DELETED = 0
;
/

-- VIEW V_COST_USER_ROLE

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "CMX"."V_COST_USER_ROLE" ("ID", "USER_ID", "USERNAME", "REAL_NAME", "ROLE_ID") AS 
  SELECT
    ur.ID,
    ur.USER_ID,
    u.USERNAME,
    u.REAL_NAME,
    ur.ROLE_ID
FROM T_COST_USER_ROLE ur
LEFT JOIN T_COST_USER u ON ur.USER_ID = u.ID AND u.DELETED = 0
;
/

